use std::io::{self, Read};
fn solve_case(s: &str) -> i32 { let mut stack = vec![-1i32]; let mut best = 0i32; for (i, ch) in s.chars().enumerate() { if ch == '(' { stack.push(i as i32); } else { stack.pop(); if stack.is_empty() { stack.push(i as i32); } else { best = best.max(i as i32 - *stack.last().unwrap()); } } } best }
fn main(){ let mut input=String::new(); io::stdin().read_to_string(&mut input).unwrap(); if input.is_empty(){return;} let lines: Vec<&str>=input.split('\n').map(|s|s.trim_end_matches('\r')).collect(); let mut idx=0usize; let t: usize=lines[idx].trim().parse().unwrap_or(0); idx+=1; let mut out=Vec::new(); for _ in 0..t { let n: usize=lines.get(idx).unwrap_or(&"0").trim().parse().unwrap_or(0); idx+=1; let s = if n > 0 { let v = lines.get(idx).copied().unwrap_or("").to_string(); idx += 1; v } else { String::new() }; out.push(solve_case(&s).to_string()); } print!("{}", out.join("\n")); }
